L("async function createAttendance(empIds) {")
L("    console.log('\\n========== 13. 考勤（正常+异常） ==========');")
L("    const client = await pool.connect();")
L("    try {")
L("        await client.query('BEGIN');")
L("        for (var ai = 0; ai < empIds.length; ai++) {")
L("            var emp = empIds[ai];")
L("            for (var ad = 0; ad < 20; ad++) { var d = new Date(); d.setDate(d.getDate() - ad); var dateStr = d.toISOString().split('T')[0]; await client.query('INSERT INTO attendance_record(id,employee_id,record_date,status,check_in_time,check_out_time,working_hours,remark,created_at) VALUES($1,$2,$3,\\'normal\\',$4,$5,8,\\'正常\\',NOW())', [uuid(), emp.id, dateStr, '08:0' + String(ad % 10), '18:0' + String(ad % 10)]); }")
L("            for (var aa = 21; aa <= 23; aa++) { var da = new Date(); da.setDate(da.getDate() - aa); await client.query('INSERT INTO attendance_record(id,employee_id,record_date,status,working_hours,remark,created_at) VALUES($1,$2,$3,\\'absent\\',0,\\'边界-旷工\\',NOW())', [uuid(), emp.id, da.toISOString().split('T')[0]]); }")
L("            var otDate = new Date(); otDate.setDate(otDate.getDate() - 24);")
L("            await client.query('INSERT INTO attendance_record(id,employee_id,record_date,status,check_in_time,check_out_time,working_hours,remark,created_at) VALUES($1,$2,$3,\\'normal\\',\\'08:00\\',\\'22:30\\',14,\\'边界-日加班6小时\\',NOW())', [uuid(), emp.id, otDate.toISOString().split('T')[0]]);")
L("            for (var al = 25; al <= 29; al++) { var dl = new Date(); dl.setDate(dl.getDate() - al); await client.query('INSERT INTO attendance_record(id,employee_id,record_date,status,check_in_time,check_out_time,working_hours,remark,created_at) VALUES($1,$2,$3,\\'late\\',\\'09:30\\',\\'18:00\\',7,\\'边界-迟到\\',NOW())', [uuid(), emp.id, dl.toISOString().split('T')[0]]); }")
L("        }")
L("        console.log('OK 考勤: ' + empIds.length + '人 x 30天（含旷工/加班/迟到异常）');")
L("        await client.query('COMMIT');")
L("    } catch (err) { await client.query('ROLLBACK'); throw err; }")
L("    finally { client.release(); }")
L("}")

L("async function createFinance(orders) {")
L("    console.log('\\n========== 14. 财务（正常+异常） ==========');")
L("    const client = await pool.connect();")
L("    try {")
L("        await client.query('BEGIN');")
L("        for (var fi = 0; fi < Math.min(3, orders.length); fi++) { var order = orders[fi]; var payId = uuid(); var amount = order.total > 0 ? order.total * 0.3 : rf(1000, 5000); await client.query('INSERT INTO payment_in(id,payment_no,source_type,amount,customer_id,customer_name,payment_method,status,order_id,remark,created_at) VALUES($1,$2,\\'order\\',$3,\\'00000000-0000-0000-0000-000000000000\\',\\'客户\\',\\'bank_transfer\\',\\'confirmed\\',$4,\\'正常收款\\',NOW())', [payId, 'PAY' + ts().slice(-8), amount, order.id]); console.log('OK 收款: ¥' + amount.toFixed(2) + ' [confirmed]'); }")
L("        var overId = uuid(); var overOrder = orders.find(o => o.total > 0) || orders[0];")
L("        if (overOrder) { await client.query(\"INSERT INTO receivable(id,dealer_id,order_id,bill_no,bill_date,due_date,amount,paid_amount,status,remark,created_at) VALUES($1,$2,$3,'BILL'+NOW()::text,DATE'2026-03-01',DATE'2026-03-15',$4,0,'overdue','边界-逾期20天',NOW())\", [overId, '00000000-0000-0000-0000-000000000000', overOrder.id, rf(10000, 30000)]); console.log('OK 边界财务: 逾期应收账款 [overdue, 逾期20天]'); }")
L("        var badId = uuid(); var badOrder = orders.find(o => o.total > 0);")
L("        if (badOrder) { await client.query(\"INSERT INTO receivable(id,dealer_id,order_id,bill_no,bill_date,due_date,amount,paid_amount,status,remark,created_at) VALUES($1,$2,$3,'BILL'+NOW()::text,DATE'2026-01-01',DATE'2026-01-15',$4,0,'bad_debt','边界-坏账(客户破产)',NOW())\", [badId, '00000000-0000-0000-0000-000000000000', badOrder.id, rf(20000, 50000)]); console.log('OK 边界财务: 坏账 [bad_debt]'); }")
L("        if (orders.length > 1 && orders[1].total > 0) { var refId = uuid(); await client.query('INSERT INTO payment_in(id,payment_no,source_type,amount,customer_id,customer_name,payment_method,status,order_id,remark,created_at) VALUES($1,$2,\\'order\\',-$3,\\'00000000-0000-0000-0000-000000000000\\',\\'客户\\',\\'bank_transfer\\',\\'refunded\\',$4,\\'边界-部分退款(产品质量问题)\\',NOW())', [refId, 'PAY' + ts().slice(-8), orders[1].total * 0.2, orders[1].id]); console.log('OK 边界财务: 部分退款 ¥' + (orders[1].total * 0.2).toFixed(2)); }")
L("        await client.query('COMMIT');")
L("    } catch (err) { await client.query('ROLLBACK'); throw err; }")
L("    finally { client.release(); }")
L("}")

L("async function verifyReports() {")
