L("        var inv = await db.query(\"SELECT m.material_name, w.warehouse_name, i.quantity FROM stock_inventory i JOIN material m ON m.id=i.material_id JOIN warehouse w ON w.id=i.warehouse_id ORDER BY i.quantity ASC NULLS LAST\");")
L("        console.log('\\n[库存（按数量升序）]'); console.table(inv.rows);")
L("        var rec = await db.query(\"SELECT order_id, amount, paid_amount, status, remark FROM receivable WHERE status IN ('overdue','bad_debt')\");")
L("        console.log('\\n[逾期/坏账应收款]'); console.table(rec.rows);")
L("        var log = await db.query(\"SELECT logistics_no, logistics_company, status, remark FROM logistics_record ORDER BY created_at DESC\");")
