L("        var inst = await db.query(\"SELECT task_no, status, accept_status, visit_status FROM installation_task ORDER BY created_at DESC\");")
L("        console.log('\\n[安装任务]'); console.table(inst.rows);")
L("        var pkg = await db.query(\"SELECT pr.package_no, pr.total_packages, (SELECT COUNT(*) FROM package_item pi WHERE pi.package_id=pr.id) as item_count, pr.remark FROM package_record pr ORDER BY pr.created_at DESC\");")
